patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..d5fc48c9ad4c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1795,7 +1795,7 @@ static Value *foldSelectInstWithICmpConst(SelectInst &SI, ICmpInst *ICI,

   ConstantRange InvDomCR = ConstantRange::makeExactICmpRegion(CPred, *CmpC);
   const APInt *OpC;
-  if (match(Op, m_BinOp(m_Specific(V), m_APInt(OpC)))) {
+  if (match(Op, m_BinOp(m_Deferred(V), m_APInt(OpC)))) {
     ConstantRange R = InvDomCR.binaryOp(
         static_cast<Instruction::BinaryOps>(Op->getOpcode()), *OpC);
     if (R == *C) {
@@ -2030,6 +2030,18 @@ Instruction *InstCombinerImpl::foldSelectInstWithICmp(SelectInst &SI,
   if (Instruction *V = foldSelectZeroOrOnes(ICI, TrueVal, FalseVal, Builder))
     return V;

+  // (not (trunc (lshr X, BW-1))) and (icmp slt X, 0) are opposites.
+  if (match(FalseVal, m_Zero())) {
+    Value *X;
+    const APInt *ShAmt;
+    if (match(SI.getCondition(),
+              m_Not(m_Trunc(m_LShr(m_Value(X), m_APInt(ShAmt))))) &&
+        match(ICI, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(X), m_ZeroInt())) &&
+        ShAmt->isPowerOf2() &&
+        ShAmt->logBase2() == X->getType()->getScalarSizeInBits() - 1)
+      return replaceInstUsesWith(SI, FalseVal);
+  }
+
   if (Value *V = foldSelectICmpLshrAshr(ICI, TrueVal, FalseVal, Builder))
     return replaceInstUsesWith(SI, V);

