' '  if (Instruction *V = foldSelectZeroOrOnes(ICI, TrueVal, FalseVal, Builder))
    return V;

  // (select (not (trunc (lshr X, BW-1))), (icmp slt X, 0), false) -> false
  // because the condition and true value are logical opposites.
  {
    Value *X;
    unsigned BW;
    if (match(SI.getCondition(),
              m_Not(m_Trunc(m_Specific(m_Shr(m_Value(X), m_APInt(BW)))))) &&
        match(ICI, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(X), m_ZeroInt())) &&
        BW + 1 == X->getType()->getScalarSizeInBits() &&
        match(FalseVal, m_Zero()))
      return replaceInstUsesWith(SI, FalseVal);
  }
'

